import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import './Navbar.css';

const navItems = [
  { label: 'Home', path: '/' },
  { 
    label: 'Resistor', 
    dropdown: [
      { label: 'Resistor Color Code', path: '/resistor-color-code' },
      { label: 'SMD Resistor Code', path: '/smd-code' }
    ]
  },
  { 
    label: 'LED', 
    dropdown: [
      { label: 'LED Resistor Calculator', path: '/led-calculator' }
    ]
  },
  { 
    label: 'Capacitor', 
    dropdown: [
      { label: 'Ceramic Capacitor Code', path: '/capacitor-code' },
      { label: 'Polyester Capacitor', path: '/capacitor-code' }, // Same page, different context usually
      { label: 'Film Capacitor', path: '/capacitor-code' }       // Same page, different context usually
    ]
  },
  { 
    label: 'Inductor', 
    dropdown: [
      { label: 'Inductor Color Code', path: '/inductor-code' }
    ]
  },
  { label: 'Voltage Divider', path: '/voltage-divider' },
  { label: 'Ohm’s Law', path: '/ohms-law' },
  { label: 'About', path: '/about' },
  { label: 'Contact', path: '/contact' },
];

export default function Navbar() {
  const location = useLocation();
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [activeDropdown, setActiveDropdown] = useState(null);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    setMenuOpen(false);
    setActiveDropdown(null);
  }, [location]);

  const toggleDropdown = (label) => {
    if (activeDropdown === label) setActiveDropdown(null);
    else setActiveDropdown(label);
  };

  return (
    <nav className={`navbar${scrolled ? ' scrolled' : ''}`}>
      <div className="nav-inner">
        <Link to="/" className="nav-logo">
          <span className="logo-icon">⚡</span>
          <span className="logo-text">PoolCalc</span>
        </Link>

        <button
          className={`hamburger${menuOpen ? ' open' : ''}`}
          onClick={() => setMenuOpen(!menuOpen)}
          aria-label="Toggle menu"
        >
          <span /><span /><span />
        </button>

        <div className={`nav-links${menuOpen ? ' open' : ''}`}>
          {navItems.map(item => (
            <div key={item.label} className={`nav-item-container${item.dropdown ? ' has-dropdown' : ''}`}>
              {item.dropdown ? (
                <>
                  <button 
                    className={`nav-link dropdown-toggle${activeDropdown === item.label ? ' active' : ''}`}
                    onClick={() => toggleDropdown(item.label)}
                  >
                    {item.label}
                    <span className="arrow">▾</span>
                  </button>
                  <div className={`dropdown-menu${activeDropdown === item.label ? ' show' : ''}`}>
                    {item.dropdown.map(sub => (
                      <Link key={sub.label} to={sub.path} className="dropdown-link">
                        {sub.label}
                      </Link>
                    ))}
                  </div>
                </>
              ) : (
                <Link
                  to={item.path}
                  className={`nav-link${location.pathname === item.path ? ' active' : ''}`}
                >
                  {item.label}
                </Link>
              )}
            </div>
          ))}
        </div>
      </div>
    </nav>
  );
}
